            for l in range(i+1, j+1, 2):
                # pair free[i] with free[l]
                # intersections with other new chords in (i+1..l-1) and (l+1..j)
                # a new chord (i,l) intersects new chord (p,q) with i<p<l<q (p in i+1..l-1, q in l+1..j)
                inter_new = 0
                for p in range(i+1, l):
